#include<stdio.h>
int count(int arr[], int n, int x) {
    int cnt = 0;
    for (int i = 0; i < n; i++) {
        if (arr[i] == x) cnt++;
    }
    return cnt;
}

int main() {
    int n, x;
    scanf("%d", &n);
    int arr[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }
    scanf("%d", &x);
    int ans = count(arr, n, x);
    printf("%d\n", ans);
    return 0;
}

