function count(arr, n, x) {
    let cnt = 0;
    for (let i = 0; i < n; i++) {
        if (arr[i] === x) cnt++;
    }
    return cnt;
}

const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});

let i = 0;
let n, x, arr;
readline.on('line', line => {
    if (i === 0) {
        n = parseInt(line);
    } else if (i === 1) {
        arr = line.split(' ').map(num => parseInt(num));
    } else if (i === 2) {
        x = parseInt(line);
        let ans = count(arr, n, x);
        console.log(ans);
        readline.close();
    }
    i++;
});
